#define fp float

__global__ void srad_kernel(
    fp lambda,
    int Nr,
    int Nc,
    long Ne,
    __global int* d_iN,
    __global int* d_iS,
    __global int* d_jE,
    __global int* d_jW,
    __global fp* d_dN,
    __global fp* d_dS,
    __global fp* d_dW,
    __global fp* d_dE,
    fp q0sqr,
    __global fp* d_c,
    __global fp* d_I)
{
    int idx = get_global_id(0);
    if (idx >= Ne) return;

    fp Jc = d_I[idx];

    fp dN = d_I[d_iN[idx]] - Jc;
    fp dS = d_I[d_iS[idx]] - Jc;
    fp dW = d_I[d_jW[idx]] - Jc;
    fp dE = d_I[d_jE[idx]] - Jc;

    d_dN[idx] = dN;
    d_dS[idx] = dS;
    d_dW[idx] = dW;
    d_dE[idx] = dE;

    fp G2 = (dN*dN + dS*dS + dW*dW + dE*dE) / (Jc*Jc);
    fp L = (dN + dS + dW + dE) / Jc;

    fp num = (0.5f*G2) - ((1.0f/16.0f)*(L*L));
    fp den = 1.0f + (0.25f*L);
    fp qsqr = num/(den*den);

    den = (qsqr-q0sqr) / (q0sqr * (1.0f+q0sqr));
    fp c = 1.0f / (1.0f+den);

    if (c < 0) c = 0;
    else if (c > 1) c = 1;

    d_c[idx] = c;
}

__global__ void srad2_kernel(
    fp lambda,
    int Nr,
    int Nc,
    long Ne,
    __global int* d_iN,
    __global int* d_iS,
    __global int* d_jE,
    __global int* d_jW,
    __global fp* d_dN,
    __global fp* d_dS,
    __global fp* d_dW,
    __global fp* d_dE,
    __global fp* d_c,
    __global fp* d_I)
{
    int idx = get_global_id(0);
    if (idx >= Ne) return;

    fp c = d_c[idx];
    fp cn = d_c[idx];
    fp cs = d_c[d_iS[idx]];
    fp cw = d_c[idx];
    fp ce = d_c[d_jE[idx]];

    fp D = cn * d_dN[idx] + cs * d_dS[idx] + cw * d_dW[idx] + ce * d_dE[idx];

    d_I[idx] = d_I[idx] + 0.25f*lambda*D;
}
